#include <stdio.h>

int main(void) {
    int n;
    double sum = 0.0;
    if (scanf("%d", &n) != 1) return 0;
    for (int i = 1; i <= n; i++) {
        sum += ((i % 2 == 1 ? 1.0 : -1.0) * (2.0 * i + 1.0) / (i * i + 1.0));
    }
    printf("result = %.3f\n", sum);
    return 0;
}
